transform_js:
const dates = []; const values = [];
rawData.rows.forEach(r => {
  dates.push(r.date);
  values.push(r.value);
});
transformedData = { dates, values };

echarts_js:
option = {
  title: {
    text: 'Interest Rate Changes (Step Line)',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis'
  },
  grid: { left: '5%', right: '5%', bottom: '15%', containLabel: true },
  xAxis: {
    type: 'category',
    data: transformedData.dates
  },
  yAxis: {
    type: 'value',
    axisLabel: { formatter: '{value} %' }
  },
  series: [
    {
      name: 'Interest Rate',
      type: 'line',
      // 'step' オプションにより階段状に描画 ('start', 'middle', 'end' が指定可能)
      step: 'end',
      data: transformedData.values,
      itemStyle: { color: '#5470c6' },
      lineStyle: { width: 3 }
    }
  ]
};
